--
-- Remove Schema Binding option from [SCore].[EntityTypesV]
--
GO
CREATE OR ALTER VIEW SCore.EntityTypesV
AS SELECT	et.ID,
		et.RowStatus,
		et.RowVersion,
		et.Guid,
		et.Name,
		et.IsReadOnlyOffline,
		et.IsRequiredSystemData,
		et.HasDocuments,
		et.LanguageLabelID,
		et.DoNotTrackChanges,
		i.Name as IconCss,
		et.IsRootEntity,
		et.DetailPageUrl
FROM	Score.[EntityTypes] et
JOIN   SUserInterface.Icons i ON et.IconId = i.ID
